:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.iat-reg-section>*{position:relative;z-index:2}\n.iat-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.iat-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.iat-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#0891b2;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(8,145,178,0.4)}\n.iat-reg-cta:hover{background:rgb(57,167,193);transform:translateY(-2px);box-shadow:0 8px 24px rgba(8,145,178,0.3)}\n.iat-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.iat-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.iat-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .iat-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .iat-reg-meta,.et_pb_section .iat-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .iat-reg-section h2{font-size:32px}\n  .iat-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.iat-reg-section *{transition:none !important}}\n/* === RELATED EVENTS === */\n.iat-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-rel-inner{max-width:1100px;margin:0 auto}\n.iat-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;margin-bottom:16px}\n.iat-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.iat-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.iat-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.iat-rel-card-border{height:4px}\n.iat-rel-card-body{padding:28px}\n.iat-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.iat-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.iat-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.iat-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.iat-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.iat-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.iat-rel-link:hover{opacity:0.8}\n\n.et_pb_section .iat-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .iat-rel-grid{grid-template-columns:1fr}\n  .iat-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.iat-rel-card{transition:none !important}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-hero-section">\n  <div class="iat-hero-superd" aria-hidden="true"></div>\n  <a href="/th/news/" class="iat-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    กลับไปข่าวสารและกิจกรรม\n  </a>\n  <span class="iat-hero-badge">งานแสดงสินค้า</span>\n  <h1>Intelligent Asia Thailand 2026</h1>\n  <p class="iat-hero-subtitle">DigiWin Thailand ร่วมกับ Digihua Smart เชิญพบปะทีมงานที่บูธ I132 — ชมระบบ e-Tax Compliance, AI Smart Manufacturing Integration และโซลูชันเชิงลึกสำหรับอุตสาหกรรมอิเล็กทรอนิกส์ พร้อมทีมที่ปรึกษาสองภาษา (ไทย-จีน) ให้คำปรึกษาตลอดงาน</p>\n\n  <div class="iat-hero-facts">\n    \n      <div class="iat-hero-fact">\n        <div class="iat-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="iat-hero-fact-value">11–13 มีนาคม 2026</div>\n        <div class="iat-hero-fact-label">อังคาร–พฤหัสบดี</div>\n      </div>\n\n      <div class="iat-hero-fact">\n        <div class="iat-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="iat-hero-fact-value">10:00 – 18:00</div>\n        <div class="iat-hero-fact-label">ทุกวัน</div>\n      </div>\n\n      <div class="iat-hero-fact">\n        <div class="iat-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="iat-hero-fact-value">ไบเทค บางนา, กรุงเทพฯ</div>\n        <div class="iat-hero-fact-label">EH 98 Hall, บูธ I132</div>\n      </div>\n\n      <div class="iat-hero-fact">\n        <div class="iat-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="iat-hero-fact-value">เข้าชมฟรี</div>\n        <div class="iat-hero-fact-label">ไม่ต้องลงทะเบียน</div>\n      </div>\n  </div>\n\n  <a href="/th/demo/" class="iat-hero-cta">\n    นัดหมายพบปะ\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Banner"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Banner: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Banner: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-ban-section">\n  <div class="iat-ban-inner">\n    <img src="data:image/jpeg;base64," alt="DigiWin x Digihua at Intelligent Asia Thailand 2026 — BITEC Bangkok, EH 98 Hall, Booth I132" class="iat-ban-img" width="1200" height="630" />\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-prob-section">\n  <div class="iat-prob-inner">\n    <span class="iat-prob-label">ทำไมต้องมาเยี่ยมชมบูธเรา</span>\n    <h2 class="iat-prob-title">ประเทศไทยคือฐานการผลิตอิเล็กทรอนิกส์ที่สำคัญ — แต่ความท้าทายด้านภาษีและ BOI ยังคงเป็นอุปสรรค</h2>\n  </div>\n  <div class="iat-prob-body">\n    \n    <p>โรงงานอิเล็กทรอนิกส์ในไทยกำลังเผชิญแรงกดดันจากหลายด้าน — ข้อกำหนด e-Tax ใหม่จากกรมสรรพากร, การตรวจสอบ BOI ที่เข้มงวดขึ้น และความต้องการระบบ Traceability แบบครบวงจรจากลูกค้าต่างชาติ</p>\n\n    <p>ที่บูธ DigiWin คุณจะได้เห็น<strong>ระบบจริงที่ทำงานอยู่ในโรงงานไทย</strong> — ไม่ใช่สไลด์หรือ PowerPoint แต่เป็นระบบ e-Tax ที่เชื่อมกรมสรรพากรได้ทันที, MES ที่ติดตามการผลิตแบบ Real-time และการเชื่อมต่อ CAD/PLM → ERP/APS → MES แบบ Full-Stack</p>\n\n    <p>DigiWin Thailand ให้บริการในไทยมากว่า 7 ปี ด้วยทีมที่ปรึกษาสองภาษา (ไทย-จีน) ที่เข้าใจอุตสาหกรรมอิเล็กทรอนิกส์และข้อกำหนดเฉพาะของประเทศไทย ไม่ว่าคุณกำลังมองหาระบบ ERP ใหม่ หรือต้องการเพิ่ม MES เข้ากับระบบที่มีอยู่ นี่คือโอกาสที่ดีที่สุดในการทำความเข้าใจสิ่งที่ DigiWin ทำได้สำหรับโรงงานของคุณ</p>\n    \n    <div class="iat-prob-data-card">\n      <div class="iat-prob-data-content">\n        <div class="iat-prob-data-number">บูธ I132</div>\n        <div class="iat-prob-data-label">EH 98 Hall, ไบเทค บางนา</div>\n      </div>\n    </div>\n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-out-section">\n  <div class="iat-out-inner">\n    <span class="iat-out-label">สิ่งที่คุณจะได้พบ</span>\n    <h2 class="iat-out-title">สามจุดเด่นหลักที่บูธ I132</h2>\n    <div class="iat-out-grid">\n      \n    <div class="iat-out-card">\n      <div class="iat-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/></svg>\n      </div>\n      <h3>ระบบ e-Tax และ BOI ครบวงจร</h3>\n      <p>ระบบที่ผ่านการรับรองจากกรมสรรพากรไทย รองรับ e-Tax, รายงาน BOI ในรูปแบบอิเล็กทรอนิกส์ และระบบภาษีศุลกากร — ระบบเดียวกันที่โรงงานไทยกว่า 100 แห่งใช้งานจริง</p>\n    </div>\n\n    <div class="iat-out-card">\n      <div class="iat-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>\n      </div>\n      <h3>การเชื่อมต่อเชิงลึกสำหรับอุตสาหกรรมอิเล็กทรอนิกส์</h3>\n      <p>DigiWin ร่วมมือกับ Digihua Smart นำเสนอระบบ ERP + MES แบบบูรณาการ ออกแบบเฉพาะสำหรับอุตสาหกรรม SMT และอิเล็กทรอนิกส์ในไทย — ทำลายปัญหาข้อมูลไม่โปร่งใสในโรงงาน</p>\n    </div>\n\n    <div class="iat-out-card">\n      <div class="iat-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>\n      </div>\n      <h3>AI Smart Manufacturing — ระบบบูรณาการครบวงจร</h3>\n      <p>ไฮไลท์หลัก: ระบบ AI เชื่อมต่อการออกแบบ (CAD/PLM) การวางแผน (ERP/APS) และการผลิต (MES) ผ่านแพลตฟอร์มข้อมูลกลาง วิเคราะห์ด้วย AI เพื่อติดตามความคืบหน้าการผลิตและสถานะเครื่องจักรแบบ Real-time</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-per-section">\n  <div class="iat-per-inner">\n    <span class="iat-per-label">งานนี้เหมาะกับใคร</span>\n    <h2 class="iat-per-title">บูธนี้ตอบโจทย์คุณหรือไม่?</h2>\n    <div class="iat-per-grid">\n      \n    <div class="iat-per-card">\n      <div class="iat-per-accent"></div>\n      <div class="iat-per-body">\n        <div class="iat-per-role">เจ้าของโรงงานอิเล็กทรอนิกส์ / ผู้จัดการโรงงาน</div>\n        <span class="iat-per-size">กำลังมองหาระบบ ERP หรือ MES</span>\n        <p class="iat-per-desc">คุณต้องการเห็นระบบจริงที่ทำงานกับข้อมูลโรงงานไทย — ไม่ใช่แค่สไลด์ คุณต้องการเข้าใจว่าระบบไหนถูกสร้างมาเพื่อโรงงานอิเล็กทรอนิกส์โดยเฉพาะ พร้อมรองรับ e-Tax และ BOI ของไทย</p>\n        <p class="iat-per-quote">"ผมต้องการเห็นระบบจริงที่รองรับ e-Tax และ BOI — ไม่ใช่แค่ PowerPoint"</p>\n      </div>\n    </div>\n\n    <div class="iat-per-card">\n      <div class="iat-per-accent"></div>\n      <div class="iat-per-body">\n        <div class="iat-per-role">ผู้ผลิตชาวไต้หวันหรือจีนในประเทศไทย</div>\n        <span class="iat-per-size">ต้องการทีมสนับสนุนสองภาษา</span>\n        <p class="iat-per-desc">คุณดำเนินการผลิตในไทยแต่สำนักงานใหญ่อยู่ไต้หวันหรือจีน คุณต้องการระบบที่เชื่อมข้อมูลข้ามประเทศได้ พร้อมทีมที่ปรึกษาที่พูดทั้งไทยและจีน เข้าใจทั้งสองวัฒนธรรม</p>\n        <p class="iat-per-quote">"เราต้องการระบบเดียวที่เชื่อมโรงงานไทยกับสำนักงานใหญ่ที่ไต้หวันได้"</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-prf-section">\n  <div class="iat-prf-inner">\n    <span class="iat-prf-label">ทำไมต้อง DigiWin</span>\n    <h2 class="iat-prf-title">เรียนรู้จากทีมที่ทำสำเร็จมาแล้วกว่า 100 โครงการ</h2>\n    <div class="iat-prf-stats-bar">\n      \n    <div class="iat-prf-stat">\n      <div class="iat-prf-stat-value">100+</div>\n      <div class="iat-prf-stat-label">โครงการในไทย</div>\n    </div>\n\n    <div class="iat-prf-stat">\n      <div class="iat-prf-stat-value">44</div>\n      <div class="iat-prf-stat-label">ปีประสบการณ์ ERP การผลิต</div>\n    </div>\n\n    <div class="iat-prf-stat">\n      <div class="iat-prf-stat-value">7</div>\n      <div class="iat-prf-stat-label">ปีให้บริการในประเทศไทย</div>\n    </div>\n\n    <div class="iat-prf-stat">\n      <div class="iat-prf-stat-value">95%</div>\n      <div class="iat-prf-stat-label">อัตราต่อสัญญาบริการ</div>\n    </div>\n    </div>\n    <p class="iat-prf-text">DigiWin Thailand ให้บริการผู้ผลิตในไทยมากว่า 7 ปี ด้วยโซลูชัน ERP, MES, WMS และ AIoT ที่สร้างมาเพื่อหน้างานโรงงานโดยเฉพาะ ที่บูธของเรา คุณจะได้พบทีมที่ปรึกษาสองภาษาที่ลงมือทำจริง — ไม่ใช่พนักงานขายที่อ่านจากสคริปต์</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-log-section">\n  <div class="iat-log-inner">\n    <span class="iat-log-label">รายละเอียดสำคัญ</span>\n    <h2 class="iat-log-title">ข้อมูลที่คุณต้องรู้</h2>\n    <div class="iat-log-grid">\n      \n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">วันที่</div>\n        <div class="iat-log-item-value">11–13 มีนาคม 2026 (อังคาร–พฤหัสบดี)</div>\n      </div>\n    </div>\n\n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">เวลา</div>\n        <div class="iat-log-item-value">10:00 – 18:00 ทุกวัน</div>\n      </div>\n    </div>\n\n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">สถานที่</div>\n        <div class="iat-log-item-value">ไบเทค บางนา, กรุงเทพฯ</div>\n      </div>\n    </div>\n\n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">หมายเลขบูธ</div>\n        <div class="iat-log-item-value">EH 98 Hall, บูธ I132</div>\n      </div>\n    </div>\n\n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">ค่าเข้าชม</div>\n        <div class="iat-log-item-value">เข้าชมฟรี</div>\n      </div>\n    </div>\n\n    <div class="iat-log-item">\n      <div class="iat-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>\n      </div>\n      <div>\n        <div class="iat-log-item-label">ข้อมูลเพิ่มเติม</div>\n        <div class="iat-log-item-value"><a href="https://www.digiwin.com.tw/news/3600.html" target="_blank" rel="noopener">อ่านบทความต้นฉบับ</a></div>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-reg-section">\n  <h2>เยี่ยมชมบูธ I132</h2>\n  <p class="iat-reg-meta">11–13 มีนาคม 2026 &middot; ไบเทค บางนา &middot; EH 98 Hall, บูธ I132</p>\n  \n  <a href="/th/demo/" class="iat-reg-cta">\n    นัดหมายพบปะ\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n  <p class="iat-reg-secondary">ไม่ต้องจอง — <a href="/th/news/">เดินเข้ามาที่บูธ I132 ได้ทุกเวลา</a> and we\'ll notify you of the next session.</p>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="iat-rel-section">\n  <div class="iat-rel-inner">\n    <span class="iat-rel-label">กิจกรรมที่กำลังจะมาถึง</span>\n    <h2 class="iat-rel-title">เรียนรู้เพิ่มเติม</h2>\n    <div class="iat-rel-grid">\n      \n    <div class="iat-rel-card">\n      <div class="iat-rel-card-border" style="background:#15803d"></div>\n      <div class="iat-rel-card-body">\n        <span class="iat-rel-badge" style="color:#15803d;background:rgba(21,128,61,0.12)">Workshop</span>\n        <h3>BOI Compliance Workshop: Production-Level Reconciliation That Passes Every Audit</h3>\n        <div class="iat-rel-meta">\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            March 15, 2026\n          </div>\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/boi-compliance-workshop/" class="iat-rel-link" style="color:#15803d">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="iat-rel-card">\n      <div class="iat-rel-card-border" style="background:#b45309"></div>\n      <div class="iat-rel-card-body">\n        <span class="iat-rel-badge" style="color:#b45309;background:rgba(180,83,9,0.12)">Factory Visit</span>\n        <h3>Live Factory Tour: See DigiWin MES in Action</h3>\n        <div class="iat-rel-meta">\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 8, 2026\n          </div>\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            EEC Industrial Zone\n          </div>\n        </div>\n        <a href="/news/events/factory-tour-mes/" class="iat-rel-link" style="color:#b45309">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="iat-rel-card">\n      <div class="iat-rel-card-border" style="background:#6d28d9"></div>\n      <div class="iat-rel-card-body">\n        <span class="iat-rel-badge" style="color:#6d28d9;background:rgba(109,40,217,0.12)">Trade Show</span>\n        <h3>Manufacturing Expo 2026: DigiWin Thailand Booth</h3>\n        <div class="iat-rel-meta">\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 20–22, 2026\n          </div>\n          <div class="iat-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            BITEC, Bangkok\n          </div>\n        </div>\n        <a href="/news/events/manufacturing-expo-2026/" class="iat-rel-link" style="color:#6d28d9">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
